<?php
namespace App\Domain\Admin\Content;use App\Domain\Inventory\Instances\Refinement\RefinementStatModifierValidator;use App\Domain\WorldCatalog\CatalogStatus;use App\Models\RefinementStatModifier;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class RefinementStatModifierContentService{private $validator;public function __construct(RefinementStatModifierValidator $validator){$this->validator=$validator;}public function save(array $data,RefinementStatModifier $modifier=null){return DB::transaction(function()use($data,$modifier){$model=$modifier?:new RefinementStatModifier();$candidate=new RefinementStatModifier($data);$this->validator->validate($candidate);$duplicate=RefinementStatModifier::where('refinement_level',$data['refinement_level'])->when($model->exists,function($q)use($model){$q->where('id','<>',$model->id);})->exists();if($duplicate)throw new InvalidArgumentException('Ya existe un modificador para este nivel.');$model->fill($data);$model->save();return$model;});}public function activate(RefinementStatModifier $modifier){return DB::transaction(function()use($modifier){$locked=RefinementStatModifier::whereKey($modifier->id)->lockForUpdate()->firstOrFail();$candidate=$locked->replicate();$candidate->status=CatalogStatus::ACTIVE;$this->validator->validate($candidate);if(RefinementStatModifier::where('refinement_level',$locked->refinement_level)->where('id','<>',$locked->id)->exists())throw new InvalidArgumentException('Duplicate refinement stat modifier.');$locked->status=CatalogStatus::ACTIVE;$locked->save();return$locked;});}public function deactivate(RefinementStatModifier $modifier){$modifier->status=CatalogStatus::INACTIVE;$modifier->save();return$modifier;}}
